stages.wvlet:
from {
  {
    from customer
    left join orders
      on c_custkey = o_custkey
      and o_comment not like '%special%requests%'
    group by c_custkey
    select c_custkey, COUNT(o_orderkey) as c_count
  }
} as c_orders
group by c_count
select c_count, COUNT(*) as custdist
order by custdist desc, c_count desc

from {
  {
    from customer
    select 
      c_custkey,
      c_name,
      { from orders where o_custkey = c_custkey select COUNT(*) } as order_count,
      { from orders where o_custkey = c_custkey select SUM(o_totalprice) }
      as total_spent
  }
} as t
where order_count > 0
select *
order by total_spent desc
limit 10

model yearly_spend(start_date: string, end_date: string) = {
    from customer
    join orders on c_custkey = o_custkey
    join lineitem on o_orderkey = l_orderkey
    join nation on c_nationkey = n_nationkey
    where n_name = 'JAPAN'
        and o_orderdate >= start_date.to_date
        and o_orderdate < end_date.to_date
    select c_name, c_acctbal, c_custkey,
        spend = (l_extendedprice * (1 - l_discount))
}

from yearly_spend('1996-01-01', '1997-01-01')
group by c_name, c_acctbal
where spend.sum > {
    from yearly_spend('1995-01-01', '1996-01-01')
    group by c_custkey
    where spend.sum > {
        from yearly_spend('1994-01-01', '1995-01-01')
        group by c_custkey
        select spend.sum.avg
    }
    select spend.sum.avg
}
select c_name, c_acctbal, spend_96 = spend.sum
order by spend_96 desc
